package applications.party.src.org.ofbiz.party.party;

public class PartyHelper { public static final String module = PartyHelper . class . getName ( ) ; private PartyHelper ( ) { } public static String getPartyName ( GenericValue partyObject ) { return getPartyName ( partyObject , false ) ; } public static String getPartyName ( Delegator delegator , String partyId , boolean lastNameFirst ) { GenericValue partyObject = null ; try { partyObject = delegator . findOne ( "PartyNameView" , UtilMisc . toMap ( "partyId" , partyId ) , false ) ; } catch ( GenericEntityException e ) { Debug . logError ( e , "Error finding PartyNameView in getPartyName" , module ) ; } if ( partyObject == null ) { return partyId ; } else { return formatPartyNameObject ( partyObject , lastNameFirst ) ; } } public static String getPartyName ( GenericValue partyObject , boolean lastNameFirst ) { if ( partyObject == null ) { return "" ; } if ( "PartyGroup" . equals ( partyObject . getEntityName ( ) ) || "Person" . equals ( partyObject . getEntityName ( ) ) ) { return formatPartyNameObject ( partyObject , lastNameFirst ) ; } else { String partyId = null ; try { partyId = partyObject . getString ( "partyId" ) ; } catch ( IllegalArgumentException e ) { Debug . logError ( e , "Party object does not contain a party ID" , module ) ; } if ( partyId == null ) { Debug . logWarning ( "No party ID found; cannot get name based on entity: " + partyObject . getEntityName ( ) , module ) ; return "" ; } else { return getPartyName ( partyObject . getDelegator ( ) , partyId , lastNameFirst ) ; } } } public static String formatPartyNameObject ( GenericValue partyValue , boolean lastNameFirst ) { if ( partyValue == null ) { return "" ; } StringBuilder result = new StringBuilder ( ) ; ModelEntity modelEntity = partyValue . getModelEntity ( ) ; if ( modelEntity . isField ( "firstName" ) && modelEntity . isField ( "middleName" ) && modelEntity . isField ( "lastName" ) ) { if ( lastNameFirst ) { if ( UtilFormatOut . checkNull ( partyValue . getString ( "lastName" ) ) != null ) { result . append ( UtilFormatOut . checkNull ( partyValue . getString ( "lastName" ) ) ) ; if ( partyValue . getString ( "firstName" ) != null ) { result . append ( ", " ) ; } } result . append ( UtilFormatOut . checkNull ( partyValue . getString ( "firstName" ) ) ) ; } else { result . append ( UtilFormatOut . ifNotEmpty ( partyValue . getString ( "firstName" ) , "" , " " ) ) ; result . append ( UtilFormatOut . ifNotEmpty ( partyValue . getString ( "middleName" ) , "" , " " ) ) ; result . append ( UtilFormatOut . checkNull ( partyValue . getString ( "lastName" ) ) ) ; } } if ( modelEntity . isField ( "groupName" ) && partyValue . get ( "groupName" ) != null ) { result . append ( partyValue . getString ( "groupName" ) ) ; } return result . toString ( ) ; } }